import{_ as e,c as t,o as a,f as n}from"./chunks/framework.BOAZPCR7.js";const m=JSON.parse('{"title":"Near real-time data on the human neutralizing antibody landscape to influenza virus as of early 2026 to inform vaccine-strain selection","description":"","frontmatter":{"layout":"post","title":"Near real-time data on the human neutralizing antibody landscape to influenza virus as of early 2026 to inform vaccine-strain selection","date":"2026-02-20T00:00:00.000Z","author":"Jesse Bloom","head":[["link",{"rel":"canonical","href":"https://jbloomlab.org/posts/2026-02-20_flu_seqneut.html"}]]},"headers":[],"relativePath":"posts/2026-02-20_flu_seqneut.md","filePath":"posts/2026-02-20_flu_seqneut.md"}'),r={name:"posts/2026-02-20_flu_seqneut.md"},o=n('<p>We just <a href="https://doi.org/10.64898/2026.02.18.706711" target="_blank" rel="noreferrer">posted to bioRxiv</a> a new study that measures the current human neutralizing antibody landscape to human seasonal influenza. These data help explain the recent spread of new subclades of H3N2 and H1N1 influenza, and can help inform the upcoming decision on which strains to choose for the 2026-2027 Northern Hemisphere influenza vaccine.</p><hr><p>A goal of our lab is to develop new methods that can characterize the forces shaping viral evolution on a timescale that is helpful for countermeasures like vaccines. Over the last few years, our lab has developed <a href="./dx.doi.org/10.17504/protocols.io.kqdg3xdmpg25/v2.html">sequencing-baed neutralization assays</a> and <a href="https://github.com/jbloomlab/seqneut-pipeline" target="_blank" rel="noreferrer">computational pipelines to analyze the data</a>. We&#39;ve now been working to leverage these tools to generate near real-time data on human neutralizing antibody immunity to influenza to inform the twice-per-year vaccine update decisions.</p><p>About six months ago we <a href="https://doi.org/10.1093/ve/veaf086" target="_blank" rel="noreferrer">posted a study</a> led by graduate student Caroline Kikawa that provided real-time data on the human neutralizing antibody landscape as of the late summer of 2025; these data were considered at the September 2025 vaccine-composition meeting for the 2026 Suthern Hemisphere vaccine. Now we&#39;ve posted <a href="https://doi.org/10.64898/2026.02.18.706711" target="_blank" rel="noreferrer">a new preprint</a> with data on the current landscape that can be used for the upcoming decision about what vaccine to use for the 2026-2027 Northern Hemisphere influenza season.</p><p>There are lots of interesting scientific findings in the study, including explanations of why subclade K of H3N2 (which is primarily responsible for the <a href="https://www.wired.com/story/what-is-super-flu-spreading-in-united-states-europe/" target="_blank" rel="noreferrer">bad influenza season this year</a>) and subclade D.3.1.1 of H1N1 have become dominant. Our results also hint at what might be next in H3N2 evolution.</p><p>In addition to reading the preprint, for more details see:</p><ul><li><a href="https://bsky.app/profile/jbloomlab.bsky.social/post/3mfd2j4ab6k2s" target="_blank" rel="noreferrer">This Bluesky thread</a>, which can be read more easily in <a href="https://skywriter.blue/pages/jbloomlab.bsky.social/post/3mfd2j4ab6k2s" target="_blank" rel="noreferrer">threaded form here</a>.</li><li><a href="https://x.com/jbloom_lab/status/2024969809600151690" target="_blank" rel="noreferrer">This X thread</a></li></ul><p>I&#39;d also note that we&#39;ve been posting the data on GitHub in real time as it was collected; Caroline recently won a <a href="https://www.experiment.foundation/beyond" target="_blank" rel="noreferrer">Beyond The Journal</a> award for this exemplary data sharing.</p><p>To access and view the data, see the following links:</p><ul><li>Computer code and numerical data: <a href="https://github.com/jbloomlab/flu-seqneut-2025to2026" target="_blank" rel="noreferrer">https://github.com/jbloomlab/flu-seqneut-2025to2026</a></li><li>Interactive visualizations of measurements: <a href="https://jbloomlab.github.io/flu-seqneut-2025to2026/" target="_blank" rel="noreferrer">https://jbloomlab.github.io/flu-seqneut-2025to2026/</a></li><li>Interactive phylogenetic trees with H3N2 titers: <a href="https://nextstrain.org/community/jbloomlab/flu-seqneut-2025to2026@main/H3N2" target="_blank" rel="noreferrer">https://nextstrain.org/community/jbloomlab/flu-seqneut-2025to2026@main/H3N2</a></li><li>Interactive phylogenetic trees with H1N1 titers: <a href="https://nextstrain.org/community/jbloomlab/flu-seqneut-2025to2026@main/H1N1" target="_blank" rel="noreferrer">https://nextstrain.org/community/jbloomlab/flu-seqneut-2025to2026@main/H1N1</a></li></ul>',10),i=[o];function s(l,h,u,p,d,c){return a(),t("div",null,i)}const b=e(r,[["render",s]]);export{m as __pageData,b as default};
